import * as React from 'react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from '../../lib/utils'

export interface FooterLink {
  label: string
  href: string
}

export interface FooterColumn {
  title: string
  links: FooterLink[]
}

export interface FooterSocial {
  platform: string
  href: string
}

const sectionCva = cva('w-full', {
  variants: {
    variant: {
      light: 'bg-[--si-body-bg] border-t border-[--si-border-color]',
      dark: 'bg-[--si-dark]',
    },
  },
  defaultVariants: { variant: 'dark' },
})

const headingCva = cva('mb-4 text-sm font-semibold uppercase tracking-widest', {
  variants: {
    variant: {
      light: 'text-[--si-heading-color]',
      dark: 'text-white',
    },
  },
  defaultVariants: { variant: 'dark' },
})

const linkCva = cva(
  'text-sm transition-colors duration-150 hover:text-[--si-primary]',
  {
    variants: {
      variant: {
        light: 'text-[--si-body-color]',
        dark: 'text-[--si-gray-400]',
      },
    },
    defaultVariants: { variant: 'dark' },
  },
)

const taglineCva = cva('mt-2 text-sm', {
  variants: {
    variant: {
      light: 'text-[--si-body-color]',
      dark: 'text-[--si-gray-400]',
    },
  },
  defaultVariants: { variant: 'dark' },
})

const bottomBarCva = cva('border-t py-6 text-sm', {
  variants: {
    variant: {
      light: 'border-[--si-border-color] text-[--si-body-color]',
      dark: 'border-white/10 text-[--si-gray-400]',
    },
  },
  defaultVariants: { variant: 'dark' },
})

