function SocialIcon({ platform, href }: FooterSocial) {
  const d = socialIconMap[platform.toLowerCase()]

  return (
    <a
      href={href}
      target="_blank"
      rel="noopener noreferrer"
      aria-label={platform}
      className="flex h-9 w-9 items-center justify-center rounded-full bg-white/5 text-[--si-gray-400] transition-all hover:bg-[--si-primary] hover:text-white"
    >
      <svg viewBox="0 0 24 24" fill="currentColor" className="h-4 w-4" aria-hidden="true">
        {d ? <path d={d} /> : <circle cx="12" cy="12" r="10" />}
      </svg>
    </a>
  )
}

export type FooterSectionVariant = 'light' | 'dark'

export interface FooterSectionProps
  extends React.HTMLAttributes<HTMLElement>,
    VariantProps<typeof sectionCva> {
  logo?: string
  tagline?: string
  columns: FooterColumn[]
  social?: FooterSocial[]
  copyright: string
}

const FooterSection = React.forwardRef<HTMLElement, FooterSectionProps>(
  (
    { className, variant = 'dark', logo, tagline, columns, social, copyright, ...props },
    ref,
  ) => (
    <footer ref={ref} className={cn(sectionCva({ variant }), className)} {...props}>
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="grid grid-cols-2 gap-8 py-12 lg:grid-cols-5 lg:py-16">
          {/* Brand column */}
          <div className="col-span-2 lg:col-span-1">
            {logo && (
              <img src={logo} alt="Logo" className="mb-4 h-8 w-auto" />
            )}
            {!logo && (
              <div className="mb-4 text-lg font-bold text-[--si-primary]">Silicon</div>
            )}
            {tagline && <p className={cn(taglineCva({ variant }))}>{tagline}</p>}

            {social && social.length > 0 && (
              <div className="mt-6 flex gap-3">
                {social.map((s) => (
                  <SocialIcon key={s.platform} {...s} />
                ))}
              </div>
            )}
          </div>

          {/* Link columns */}
          {columns.map((col) => (
            <div key={col.title}>
              <h3 className={cn(headingCva({ variant }))}>{col.title}</h3>
              <ul className="space-y-3">
                {col.links.map((link) => (
                  <li key={link.href}>
                    <a href={link.href} className={cn(linkCva({ variant }))}>
                      {link.label}
                    </a>
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>

        <div className={cn(bottomBarCva({ variant }))}>
          <p>{copyright}</p>
        </div>
      </div>
    </footer>
  ),
)
FooterSection.displayName = 'FooterSection'

export { FooterSection }
